### Generate function to compare two models using LRT
compare_models_lrt <- function(model1, model2) {
  log_like_1 <- logLik(model1)
  log_like_2 <- logLik(model2)
  lr_test <- -2 * (as.numeric(log_like_1) - as.numeric(log_like_2))
  df <- attr(log_like_2, "df") - attr(log_like_1, "df")
  p_value <- pchisq(lr_test, df = df, lower.tail = FALSE)
  return(list(
    lr_test_statistic = lr_test,
    df = df,
    p_value = p_value
  ))
}




