### 6.3 Generate Kaplan-Meier survival curves----

for (i in seq(1,7)) {
  ### Define model options
  model_options = list(results_clin$model, results_clin_mri$model, results_clin_meg_alpha_gamma1$model, results_clin_plasma$model,
                       results_clin_ab$model, results_clin_tau$model, results_all$model, 
                       results_clin_plasma_211$model, results_clin_ab_226$model, results_clin_tau_224$model)
  model_colors = c("gray5", "gray50","#F23F43","#FF7F50", "#1E98DD","#7600BC", "#00BA38", "#FF7F50","#1E98DD","#7600BC")
  model_names = c("clin","clin_mri","clin_meg","clin_plasma","clin_ab","clin_tau","all","clin_plasma_211","clin_ab_226","clin_tau_224")
  
  ### Select model
  model = model_options[[i]]; model_color = model_colors[i]; model_name = model_names[i]
  
  if (i %in% seq(1, 7)) { x_limits = c(0, 7.5); y_limits = c(0.6, 1); breaks = seq(0.6, 1, by = 0.1) }
  if (i %in% c(8)) { x_limits = c(0, 11.2); y_limits = c(0.45, 1); breaks = 1 }
  if (i %in% c(9, 10)) { x_limits = c(0, 7.5); y_limits = c(0.45, 1); breaks = 1 }
  
  ### Generate plot
  p = ggsurvplot(
    fit = survfit(model), 
    data = data_meg_pet_cogn3, 
    xlab = "Time (years)", 
    ylab = "Survival Probability",
    xlim = x_limits, 
    breaks = breaks, 
    ylim = y_limits, 
    palette = model_color, 
    conf.int = TRUE, 
    conf.int.fill = model_color,
    conf.int.alpha = 0.1,
    conf.int.style = "ribbon", 
    surv.median.line = "none",
    risk.table = FALSE, 
    ggtheme = theme_classic() +
      theme(
        axis.title.x = element_text(size = 16),
        axis.title.y = element_text(size = 16),
        axis.text.x = element_text(size = 14),
        axis.text.y = element_text(size = 14)
      ),
    legend = "none"
  )
  
  g = p$plot +
    geom_step(aes(y = upper), color = model_color, linetype = "solid", size = 0.6, alpha = 1) +
    geom_step(aes(y = lower), color = model_color, linetype = "solid", size = 0.6, alpha = 1) +
    scale_x_continuous(limits = x_limits, breaks = seq(0, 11, by = 1)) + 
    scale_y_continuous(limits = y_limits, breaks = seq(0.5, 1, by = 0.1)) 
  
  
  print(g)
  ggsave(paste0("cox_surv_curve_", model_name, ".png"), plot = g, units = "in", width = 4, height = 4, dpi = 3000, bg = "white", path = path)
}

