### 7. Assess correlation between risk scores and  biomarkers----

### Change labels for APOE
data_meg_pet_cogn3$apoe <- factor(data_meg_pet_cogn3$apoe, levels = c(0, 1), labels = c("Non-carrier", "Carrier"))

model_options=list(results_clin$model, results_clin_meg_alpha_gamma1$model, results_clin_mri$model, results_clin_plasma$model,
                   results_clin_ab$model, results_clin_tau$model, results_all$model, 
                   results_clin_plasma_211$model, results_clin_ab_226$model, results_clin_tau_224$model)


### Create function to run correlations and t-tests between the risk scores and biomarkers
### as well as ANOVAs and x2 to test for the effect of risk group

compare_risk_groups <- function(variable_name, variable_type, model, data, y_label, custom_colors, model_fit, path) {
  if (model == "clin") {
    risk_scores <- predict(model_options[[1]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
    
  }
  if (model == "clin_meg") {
    risk_scores <- predict(model_options[[2]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  if (model == "clin_mri") {
    risk_scores <- predict(model_options[[3]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  if (model == "clin_plasma") {
    risk_scores <- predict(model_options[[4]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  if (model == "clin_ab") {
    risk_scores <- predict(model_options[[5]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  if (model == "clin_tau") {
    risk_scores <- predict(model_options[[6]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  if (model == "all") {
    risk_scores <- predict(model_options[[7]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  if (model == "clin_plasma_211") {
    risk_scores <- predict(model_options[[8]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }  
  if (model == "clin_ab_226") {
    risk_scores <- predict(model_options[[9]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  if (model == "clin_tau_224") {
    risk_scores <- predict(model_options[[10]], type = "lp");
    risk_group=cut(risk_scores, breaks = quantile(risk_scores, probs = c(0, 1/3, 2/3, 1)), 
                   labels = c("Low", "Medium", "High"), include.lowest = TRUE)
    data$risk_group=risk_group; data$risk_scores=risk_scores
  }
  
  ### Log-rank test tests to contrast risk groups
  if (model %in% c("clin", "clin_meg", "clin_mri", "clin_plasma", "clin_ab", "clin_tau", "all")) {
    log_rank_test=survdiff(Surv(diff_years_meg_mci_cox, mci_status_cox) ~ risk_group, data = data)
  }
  if (model %in% c("clin_plasma_211")) {
    log_rank_test=survdiff(Surv(diff_years_plasma_mci_cox, mci_status_cox) ~ risk_group, data = data)
  }
  if (model %in% c("clin_ab_226", "clin_tau_224")) {
    log_rank_test=survdiff(Surv(diff_years_pet_mci_cox, mci_status_cox) ~ risk_group, data = data)
  }
  
  #capture.output(log_rank_test, file = paste0(path, "/log_rank_test_risk_groups_", model, ".txt"))
  chi_log_rank=log_rank_test$chisq
  p_val_log_rank=log_rank_test$pvalue
  if (model %in% c("clin", "clin_meg", "clin_mri", "clin_plasma", "clin_ab", "clin_tau", "all")) {
    pair_log_rank=pairwise_survdiff(Surv(diff_years_meg_mci_cox, mci_status_cox) ~ risk_group, data = data, p.adjust.method = "fdr")
  }
  if (model %in% c("clin_plasma_211")) {
    pair_log_rank=pairwise_survdiff(Surv(diff_years_plasma_mci_cox, mci_status_cox) ~ risk_group, data = data, p.adjust.method = "fdr")
  }
  if (model %in% c("clin_ab_226", "clin_tau_224")) {
    pair_log_rank=pairwise_survdiff(Surv(diff_years_pet_mci_cox, mci_status_cox) ~ risk_group, data = data, p.adjust.method = "fdr")
  }
  
  #capture.output(pair_log_rank, file = paste0(path, "/pair_log_rank_risk_groups_", model, ".txt"))
  low_vs_medium=pair_log_rank$p.value[1]
  low_vs_high=pair_log_rank$p.value[2]
  medium_vs_high=pair_log_rank$p.value[4]
  
  
  ### Define color for scatterplot depending on type of biomaker
  if(variable_name %in% c("age_z", "sex", "education_z", "apoe")){
    color=model_colors[1]}
  if(variable_name %in% c("tau_meta_roi_meg_alpha_z", "tau_meta_roi_meg_gamma1_z")){
    color=model_colors[2]}
  if(variable_name %in% c("hippocampal_volume_z")){
    color=model_colors[3]}
  if(variable_name %in% c("Ab42_40_ratio_z", "ptau_217_z")){
    color=model_colors[4]}
  if(variable_name %in% c("amyloid_index_z")){
    color=model_colors[5]}
  if(variable_name %in% c("tau_entorhinal_z")){
    color=model_colors[6]}
  
  # Construct formula dynamically
  formula <- as.formula(paste("risk_scores ~", variable_name))
  formula_groups <- as.formula(paste(variable_name, "~ risk_group"))
  
  ### For continuous variables
  if (variable_type == "continuous") {
    
    # Calculate linear association with continuous risk scores
    cor_risk=summary(lm(formula, data = data))
    t_value_risk_score=cor_risk$coefficients[variable_name, "t value"]
    p_value_risk_score=cor_risk$coefficients[variable_name, "Pr(>|t|)"]
    #capture.output(cor_risk, file = paste0(path, "/lm_", variable_name, "_risk_score_", model, ".txt"))
    
    
    if(model_fit=="linear"){
      p = ggplot(data = data, aes(x = .data[[variable_name]], y = risk_scores)) +
        geom_point(color = color, alpha = 0.5, size = 3.5) +
        geom_smooth(color = color, fill = color, alpha = 0.2,
                    linewidth = 1.5, method = "lm", se = TRUE) +
        labs(y = "Relative risk score", x = y_label) +
        scale_y_continuous(labels = scales::label_number(accuracy = 1)) +
        theme_classic() +
        theme(axis.title = element_text(size = 20),
              axis.text = element_text(size = 18))
      
      
      plot_filename <- paste0(path, "/scatter_risk_score_", variable_name, "_", model, ".png")
      ggsave(plot_filename, plot = p, units = "in", width = 4, height = 4, dpi = 3000, bg = "white")
    }
    
    if(model_fit=="nl"){
      p = ggplot(data = data, aes(x = .data[[variable_name]], y = risk_scores)) +
        geom_point(color = color, alpha = 0.5) +
        geom_smooth(method = "lm", formula = y ~ poly(x, 2),
                    color = color, fill = color,
                    alpha = 0.05, linewidth = 1.5, se = TRUE) +
        labs(y = "Risk score", x = y_label) +
        scale_y_continuous(labels = scales::label_number(accuracy = 1)) +
        theme_classic() +
        theme(axis.title = element_text(size = 20),
              axis.text = element_text(size = 18))
      
      plot_filename <- paste0(path, "/scatter_risk_score_", variable_name, "_", model, "_nl.png")
      ggsave(plot_filename, plot = p, units = "in", width = 4, height = 4, dpi = 3000, bg = "white")
    }
    
    
    
    # Perform ANOVA
    aov_model <- aov(formula_groups, data = data)
    aov_summary <- summary(aov_model)
    p_value_aov <- aov_summary[[1]][["Pr(>F)"]][1]
    F_value_aov <- aov_summary[[1]][["F value"]][1]
    #capture.output(aov_summary, file = paste0(path, "/aov_", variable_name, "_risk_group_", model, ".txt"))
    posthoc_tukey <- TukeyHSD(aov(formula_groups, data = data))
    p_vals_fdr_tukey <- posthoc_tukey[["risk_group"]][, "p adj"]
    low_vs_medium_tukey=p_vals_fdr_tukey[1]
    low_vs_high_tukey=p_vals_fdr_tukey[2]
    medium_vs_high_tukey=p_vals_fdr_tukey[3]
    
    # Generate violin plot
    p <- ggplot(data, aes(x = risk_group, y = .data[[variable_name]], fill = risk_group)) +
      geom_violin(trim = FALSE) +
      scale_fill_manual(values = custom_colors) +
      geom_boxplot(width = 0.3, outlier.shape = NA) +
      geom_jitter(shape = 16, position = position_jitter(0.1), size = 1) +
      labs(y = y_label, x = "Risk group") +
      My_Theme + theme_modern() + 
      theme(legend.position = "none", 
            axis.title.x = element_text(margin = margin(t = 5, unit = "pt")),
            axis.title.y = element_text(margin = margin(r = 5, unit = "pt")))
    
    # Save the plot
    plot_filename <- paste0(path, "/violin_risk_group_", variable_name, "_", model, ".png")
    #ggsave(plot_filename, plot = p, units = "in", width = 4, height = 4, dpi = 600, bg = "white")
    
    return(list(lm_summary = cor_risk, t_val_risk_score = t_value_risk_score, p_value_risk_score = p_value_risk_score, 
                aov_summary = aov_summary,  F_value_aov = F_value_aov, p_value_aov = p_value_aov,
                posthoc_tukey = posthoc_tukey, p_vals_fdr_tukey = p_vals_fdr_tukey,
                low_vs_medium_tukey=low_vs_medium_tukey,low_vs_high_tukey=low_vs_high_tukey,medium_vs_high_tukey=medium_vs_high_tukey,
                log_rank_test=log_rank_test, chi_log_rank=chi_log_rank, p_val_log_rank=p_val_log_rank,
                pair_log_rank=pair_log_rank, pair_log_low_vs_medium=low_vs_medium,
                pair_log_low_vs_high=low_vs_high,pair_log_medium_vs_high=medium_vs_high))
  }
  
  ### For categorical variables
  if (variable_type == "categorical") {
    
    ### Association with risk scores
    cor_risk=t.test(formula, data = data)
    t_value_risk_score=cor_risk$statistic
    p_value_risk_score=cor_risk$p.value
    
    #capture.output(cor_risk, file = paste0(path, "/t_", variable_name, "_risk_score_", model, ".txt"))
    
    p=ggplot(data, aes(x = .data[[variable_name]], y = risk_scores, fill = .data[[variable_name]])) +
      geom_violin(trim = FALSE) +
      geom_boxplot(width = 0.3) + geom_jitter(width = 0.15, color = "black", alpha = 0.25, size = 3.5) + 
      scale_fill_manual(values = c( "gray75", "gray75")) +  # Example colors
      labs(x = y_label, y = "Relative risk score") +
      scale_y_continuous(breaks = seq(-2, 4, by = 2)) + 
      theme_classic() +   theme(legend.position = "none") +
      theme(axis.title = element_text(size = 20), axis.text = element_text(size = 18))
    plot_filename <- paste0(path, "/box_risk_score_", variable_name, "_", model, ".png")
    ggsave(plot_filename, plot = p, units = "in", width = 4, height = 4, dpi = 3000, bg = "white")
    
    
    # Perform Chi-square test
    table_risk <- table(data[[variable_name]], data$risk_group)
    table_risk <- t(table_risk)
    chi_square_result <- chisq.test(table_risk)
    p_value_x2 <- chi_square_result$p.value
    x2_value <- chi_square_result$statistic
    #capture.output(chi_square_result, file = paste0(path, "/chi_", variable_name, "_risk_group_", model, ".txt"))
    pair_chi=pairwise.prop.test(table_risk, p.adjust.method = "fdr")
    low_vs_medium_pair_chi=pair_chi$p.value[1]
    low_vs_high_pair_chi=pair_chi$p.value[2]
    medium_vs_high_pair_chi=pair_chi$p.value[4]
    
    # Convert categorical variable to factor
    data[[variable_name]] <- as.factor(data[[variable_name]])
    
    # Generate stacked bar plot with distinct colors for each risk group-category combination
    p <- ggplot(data, aes(x = risk_group, fill = interaction(risk_group, .data[[variable_name]]))) +
      geom_bar(position = "stack") +
      labs(x = "Risk group", y = "Number of subjects", fill = y_label) + 
      theme_classic() +  
      scale_fill_manual(values = custom_colors_cat) +  
      My_Theme + theme_modern() + 
      theme(legend.position = "none",
            axis.title.x = element_text(margin = margin(t = 5, unit = "pt")),
            axis.title.y = element_text(margin = margin(r = 5, unit = "pt")))
    
    # Save the plot
    plot_filename <- paste0(path, "/stacked_bar_risk_group_", variable_name, "_", model, ".png")
    #ggsave(plot_filename, plot = p, units = "in", width = 5, height = 5, dpi = 600, bg = "white")
    
    return(list(cor_risk_result = cor_risk, t_value_risk_score = t_value_risk_score, p_value_risk_score = p_value_risk_score,
                pair_chi=pair_chi, low_vs_medium_pair_chi=low_vs_medium_pair_chi,
                low_vs_high_pair_chi=low_vs_high_pair_chi, medium_vs_high_pair_chi=medium_vs_high_pair_chi,
                chi_square_result = chi_square_result, x2_value = x2_value, p_value_x2 = p_value_x2,
                table_risk=table_risk))
  }
}



