### 8.2 Plot interaction effect: Hazard ratio change over time----

### Generate function to plot change in Hazard ratio over time from the interaction coefficients 

plot_time_varying_hr_with_ci <- function(cox_model, var_name, time_max = 7, n_points = 100, 
                                         color = "#ffbe0b", path = ".", ylim_fixed = "no") {
  
  # Extract coefficients
  coef_main <- coef(cox_model)[[var_name]]
  coef_tt <- coef(cox_model)[[paste0("tt(", var_name, ")")]]
  
  # Extract variance-covariance matrix
  vcov_matrix <- vcov(cox_model)
  var_main <- vcov_matrix[var_name, var_name]
  var_tt <- vcov_matrix[paste0("tt(", var_name, ")"), paste0("tt(", var_name, ")")]
  cov_main_tt <- vcov_matrix[var_name, paste0("tt(", var_name, ")")]
  
  # Define time range
  time_seq <- seq(0, time_max, length.out = n_points)
  
  # Compute linear predictor and variance
  lp_time <- coef_main + coef_tt * time_seq
  var_lp_time <- var_main + (time_seq^2) * var_tt + 2 * time_seq * cov_main_tt
  
  # Confidence intervals
  se_lp_time <- sqrt(var_lp_time)
  lower_lp <- lp_time - 1.96 * se_lp_time
  upper_lp <- lp_time + 1.96 * se_lp_time
  
  # HR and CI
  HR_time <- exp(lp_time)
  HR_lower <- exp(lower_lp)
  HR_upper <- exp(upper_lp)
  
  # Create dataframe
  df_hr <- data.frame(Time = time_seq, HR = HR_time, HR_lower = HR_lower, HR_upper = HR_upper)
  
  # Estimate the time where HR = 1
  time_hr1 <- if (coef_tt != 0) -coef_main / coef_tt else NA
  
  # Y-segment for HR=1 vertical annotation
  y_max <- if (ylim_fixed == "yes") 2 else max(df_hr$HR_upper, na.rm = TRUE)
  y_seg_end <- y_max / 3
  
  # Base plot
  p <- ggplot(df_hr, aes(x = Time, y = HR)) +
    geom_line(color = color, linewidth = 1.2) +
    geom_ribbon(aes(ymin = HR_lower, ymax = HR_upper), fill = color, alpha = 0.2) +
    geom_hline(yintercept = 1, linetype = "dashed", color = "gray") +
    labs(x = "Years from biomarker", y = "Hazard ratio") +
    theme_classic() +
    theme(axis.title = element_text(size = 20), axis.text = element_text(size = 18))
  
  # Add integer-only breaks and optional fixed limits
  if (ylim_fixed == "yes") {
    p <- p + 
      scale_y_continuous(limits = c(0,6), breaks = c(0:6), labels = as.character(0:2))
  } else {
    p <- p + 
      scale_y_continuous(
        breaks = function(x) {
          bks <- pretty(x)
          bks_int <- unique(round(bks))
          bks_int[bks_int >= min(x) & bks_int <= max(x)]
        },
        labels = scales::label_number(accuracy = 1)
      )
  }
  
  # Add vertical dashed line BELOW HR=1 and annotation below
  if (!is.na(time_hr1) && time_hr1 >= 0 && time_hr1 <= time_max) {
    p <- p +
      annotate("segment",
               x = time_hr1, xend = time_hr1,
               y = 1, yend = 1 - (y_seg_end * 0.5),
               color = "gray50", linetype = "dashed") +
      annotate("text",
               x = time_hr1,
               y = 1 - (y_seg_end * 0.5),
               label = "HR = 1",
               hjust = 0.5, vjust = 1.2,
               size = 5, color = "gray40")
  }
  
  # Save and return
  ggsave(filename = paste0(var_name, "_HR_over_time_with_CI.png"), plot = p,
         units = "in", width = 4, height = 4, dpi = 3000, bg = "white", path = path)
  
  return(p)
}




