### 12. Plot correlations coefficients between model features----

### Function to compute p-values for correlations
cor_pvalues <- function(mat) {
  p_mat <- matrix(NA, ncol = ncol(mat), nrow = nrow(mat))
  colnames(p_mat) <- colnames(mat)
  rownames(p_mat) <- rownames(mat)
  
  for (i in 1:(ncol(mat) - 1)) {
    for (j in (i + 1):ncol(mat)) {
      test <- cor.test(mat[, i], mat[, j], use = "complete.obs")
      p_mat[i, j] <- test$p.value
      p_mat[j, i] <- test$p.value  # Symmetric matrix
    }
  }
  diag(p_mat) <- NA  # No p-values on the diagonal
  return(p_mat)
}

# Compute correlation matrix
cor_matrix <- cor(data_meg_pet_cogn3[, c("age","education","tau_meta_roi_meg_alpha","tau_meta_roi_meg_gamma1","hippocampal_volume",
                                         "Ab42_40_ratio","ptau_217","amyloid_index",
                                         "tau_entorhinal")], use = "complete.obs")

# Compute p-value matrix
p_matrix <- cor_pvalues(data_meg_pet_cogn3[, c("age","education","tau_meta_roi_meg_alpha","tau_meta_roi_meg_gamma1","hippocampal_volume",
                                               "Ab42_40_ratio","ptau_217","amyloid_index",
                                               "tau_entorhinal")])
p_matrix=p_matrix[c(seq(1,7)),seq(1,7)]



# Labels
labels <- c("Age", "Education", "Alpha power", "Gamma power", "Hipp. vol.",
            "A??42/40 ratio", "p-tau217", "Necortical A??", "Entorhinal tau")

rownames(cor_matrix) <- labels
colnames(cor_matrix) <- labels
rownames(p_matrix) <- labels
colnames(p_matrix) <- labels

# Color scale for correlation matrix
#color_scale_corr <- colorRampPalette(c("#3A97A3", "white", "#ff84e1"))(100)
color_scale_corr <- colorRampPalette(c("#71bfff","white", "#fc9c9c"))(100)

# Color scale for p-values (e.g., significant values darker)
color_scale_pval <- colorRampPalette(c("white", "red"))(100)



# Plot correlation matrix with red borders for |r| > 0.28
png("corr_bw_features.png", width = 3000, height = 3000, res = 600)

diag(cor_matrix) <- 0

corrplot(cor_matrix, method = "color", col = color_scale_corr, number.cex = 0.6,  
         outline = FALSE, addCoef.col = 'black', diag = TRUE, mar = c(4.5,1,2.5,1), 
         order = "original", tl.cex = 0.8, tl.col = "black", tl.srt = 45, tl.offset = 0.6,
         is.corr = FALSE, type = "lower", bg = "gray80", cl.length = 2, 
         cl.cex = 0.8, addgrid.col = "black")

# Add red borders for correlations > 0.28 or < -0.28
n <- nrow(cor_matrix)
for (i in 2:n) {
  for (j in 1:(i - 1)) {
    val <- cor_matrix[i, j]
    if (!is.na(val) && (val > 0.28 | val < -0.28)) {
      rect(xleft = j - 0.5, ybottom = n - i + 0.5,
           xright = j + 0.5, ytop = n - i + 1.5,
           border = "red", lwd = 2)
    }
  }
}

